#!/usr/bin/env node
/**
 * expand-windows-extras.js
 *
 * Adds CITY_WINDOW_SUPPLEMENTAL, CITY_WINDOW_EXTRA, CITY_WINDOW_EXTRA2, and
 * CITY_WINDOW_COMPLEX entries for 10 new flagship metros into
 * scripts/build-flagship-windows.js.
 *
 * Each entry uses genuinely unique, city-specific content so 8-word shingle
 * overlap between any two metros stays below 10%.
 *
 * Usage: node scripts/expand-windows-extras.js [--dry]
 */

const fs = require("fs");
const path = require("path");

const DRY = process.argv.includes("--dry");
const FILE = path.resolve(__dirname, "build-flagship-windows.js");

let src = fs.readFileSync(FILE, "utf8");

/* ======================================================================
 * Helper: inject entries before the closing }; of a named dict.
 * Pattern: finds `const DICT_NAME = {` ... `};` and inserts before `};`
 * ====================================================================== */
function injectIntoDict(source, dictName, newEntries) {
  // Find the dict's closing `};` by matching from the const declaration.
  // We look for the LAST `};` that closes this specific dict by finding
  // the merge-loop that follows it.
  const declPattern = new RegExp(`const ${dictName} = \\{`);
  const declMatch = declPattern.exec(source);
  if (!declMatch) {
    console.error(`Could not find declaration for ${dictName}`);
    process.exit(1);
  }
  const startIdx = declMatch.index + declMatch[0].length;

  // Find the closing `};` for this dict. We need to track brace depth.
  let depth = 1;
  let i = startIdx;
  while (i < source.length && depth > 0) {
    if (source[i] === "{") depth++;
    else if (source[i] === "}") depth--;
    i++;
  }
  // i now points just after the closing `}` of the dict
  // The `};` is at position (i-1) for `}` and i for `;`
  const insertPos = i - 1; // just before the closing `}`

  // Build the text to insert
  const insertText = "\n" + newEntries + "\n";

  return source.slice(0, insertPos) + insertText + source.slice(insertPos);
}

